export default function startScreen(){const e=Array.from(document.querySelectorAll(".start-screen__footer_projects-slider_slide"));let t=0,r=e[t],i=document.querySelector(".start-screen__footer_projects");i.querySelector(".start-screen__footer_projects-slider-nav_right").addEventListener("click",()=>{t<e.length-1?t++:t=0,r.animate([{opacity:1},{opacity:0}],{duration:300,fill:"forwards",easing:"linear"}).onfinish=()=>{r.classList.add("hidden"),r=e[t],r.style.opacity=.5,r.classList.remove("hidden"),r.animate([{opacity:.5},{opacity:1}],{duration:300,fill:"forwards",easing:"linear"})}}),i.querySelector(".start-screen__footer_projects-slider-nav_left").addEventListener("click",()=>{0==t?t=e.length-1:t--,r.animate([{opacity:1},{opacity:0}],{duration:300,fill:"forwards",easing:"linear"}).onfinish=()=>{r.classList.add("hidden"),r=e[t],r.style.opacity=.5,r.classList.remove("hidden"),r.animate([{opacity:0},{opacity:1}],{duration:300,fill:"forwards",easing:"linear"})}})}